var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_HALLOWEEN_NULL","text":{"KOREA":"아아...... 그래. 언젠가 이런 형태로 만나기를 고대하고 있었지.","JPN":"ああ……そう。いつかこういう形で会うのを楽しみにしていたわ。","ENG":"Aah... Yes, I've been looking forward to seeing you like this.","TWN":"啊啊……是啊，我期待有一天能以這種形式見面。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_HALLOWEEN_NULL","text":{"KOREA":"기억도 흐릿해질 만큼 수없이 우리를 방해해 온 눈엣가시 같은 적......","JPN":"数え切れないほど、何度も私たちを妨害してきた敵……","ENG":"A perpetual thorn in my side that's interfered with us more times than I can remember.","TWN":"依稀還記得…在我們的眼前有無數的敵人試圖阻礙我們.……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_HALLOWEEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_HALLOWEEN_NULL","text":{"KOREA":"그런 자를 위해 몸을 던져야 하는 처지라니.","JPN":"そんな者のために献身しなければならない立場になるなんて。","ENG":"I can't believe I have to offer myself for someone like that.","TWN":"難道要爲那種人奮不顧身嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_HALLOWEEN_NULL","text":{"KOREA":"후훗...... 후후훗...... 후후후훗......","JPN":"ふふっ……ふふふっ……ふふふふっ……","ENG":"Hah hah... Hah hah hah. Hah hah hah hah! ","TWN":"嘻嘻……嘻嘻嘻……嘻嘻嘻嘻……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_HALLOWEEN_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_HALLOWEEN_NULL","text":{"KOREA":"아아, 정말이지 최고야. 머릿속이 녹아내려 버릴 것 같을 정도로...... 훌륭해.","JPN":"ああ、本当に最高だわ。脳が溶けてしまうほどに……素晴らしい。","ENG":"Ah, this is incredible. I feel as if my brain is melting. How ecstatic! ","TWN":"啊…真是太棒了。彷彿腦子都快溶化般的美妙。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_HALLOWEEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_HALLOWEEN_NULL","text":{"KOREA":"더욱 거칠게 다루어 주면 좋으련만, 얌전한 척 하는 네게 당장은 바라기 어렵겠지.","JPN":"もっと手荒に扱ってくれればいいのに、猫をかぶっているあなたに今すぐそれは無理なのね。","ENG":"I'd love you to treat me more roughly, but you're still being too coy.","TWN":"雖然希望你能更粗暴一點，但實在很難對故作斯文的你有所期待啊。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_HALLOWEEN_NULL","text":{"KOREA":"하지만 알고 있다. 사람이란 것들이 얼마나 가혹해질 수 있는지.","JPN":"でも、知っているのよ。人間というものがどれだけ残酷になれるかを。","ENG":"But I know how cruel you humans really are.","TWN":"但我知道，人會變得多麼殘酷。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_HALLOWEEN_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_HALLOWEEN_NULL","text":{"KOREA":"그토록 오랜 시간 갇혀 있었는데도 눈에 선해.","JPN":"どれほど長い間閉じ込められていても、鮮明に覚えているわ。","ENG":"I was locked away for such a long time, but I still remember it as if it were yesterday. ","TWN":"被關了那麼長時間，還是歷歷在目。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_HALLOWEEN_NULL","text":{"KOREA":"스스로 망가지는 것도 모르는 채...... 눈에 핏발을 세우고 내게 고통을 바치던 천한 것들이.","JPN":"自分が壊れていることにも気付かないまま……血走った目で苦しみを捧げていた卑しい者たちを。","ENG":"How so eager those insignificant beings were to offer me pain, not knowing the damage they inflicted upon themselves.","TWN":"甚至連自己已經毀壞了都不知道……那帶著充血的眼睛給予了我苦痛的卑劣之人。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_HALLOWEEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_HALLOWEEN_NULL","text":{"KOREA":"자아, 그러니 너의 가장 저열한 욕망으로 나를 학대해 다오.","JPN":"さあ、だからあなたの最も汚い欲望で私を虐待してちょうだい。","ENG":"So, now, torment me and satisfy your basest desires. ","TWN":"來，就用你最低劣的慾望來對待我吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_HALLOWEEN_NULL","text":{"KOREA":"네가 상상하는 가장 끔찍한 고통 속에서 몸부림칠 수 있게.","JPN":"あなたの想像する最も残虐な苦しみの中で悶えられるように。","ENG":"Let me writhe in the greatest pain you can muster. ","TWN":"就讓我想像自己在最為恐懼的痛苦裡掙扎。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_HALLOWEEN_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_HALLOWEEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_HALLOWEEN_NULL","text":{"KOREA":"연민하는 눈길이라. 후훗. 가슴이 미어지는군.","JPN":"同情の視線。ふふっ。胸が張り裂けそうだわ。","ENG":"I can see the sympathy in your eyes. Hah hah. It's making my heart ache.","TWN":"憐憫的眼神，嘻嘻，我的心好痛啊。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_HALLOWEEN_NULL","text":{"KOREA":"거절하더라도 상관없겠지. 네 포악한 본능을 일깨워 줄 시간은...... 아직 많으니.","JPN":"断っても構わないわ。あなたの暴悪な本能を目覚めさせる時間は……まだ充分あるから。","ENG":"I'll understand even if you say no. There's plenty of time for me to awaken you to your violent nature.","TWN":"拒絕也沒關係。喚醒你兇惡本能的時間……還有很多。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_HALLOWEEN_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};